const input = $json.body ?? $json;
const required = ['project_id', 'entity_type', 'title', 'content', 'source'];
for (const key of required) {
  const value = input[key];
  if (value === undefined || value === null || String(value).trim() === '') {
    throw new Error(`Missing required field: ${key}`);
  }
}

if (!Array.isArray(input.vector) || input.vector.length === 0) {
  throw new Error('Missing required field: vector[]');
}

const vector = input.vector.map((value, index) => {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) {
    throw new Error(`Invalid vector value at index ${index}`);
  }
  return numeric;
});

const normalizeNullable = (value) => {
  if (value === undefined || value === null) return null;
  const normalized = String(value).trim();
  return normalized === '' ? null : normalized;
};

const tags = Array.isArray(input.tags)
  ? input.tags.map((tag) => String(tag).trim()).filter((tag) => tag !== '')
  : [];

const createdAt = normalizeNullable(input.created_at) ?? new Date().toISOString();
const title = String(input.title).trim();
const entityType = String(input.entity_type).trim();
const source = String(input.source).trim();
const projectId = String(input.project_id).trim();
const sequenceId = normalizeNullable(input.sequence_id);
const sceneId = normalizeNullable(input.scene_id);
const shotId = normalizeNullable(input.shot_id);
const pointId = normalizeNullable(input.point_id) ?? [projectId, sequenceId ?? 'root', sceneId ?? 'root', shotId ?? 'root', entityType, Date.now()].join(':');
const collection = normalizeNullable(input.collection) ?? 'cine_project_context';

return [{
  json: {
    collection,
    point_id: pointId,
    point: {
      id: pointId,
      vector,
      payload: {
        project_id: projectId,
        sequence_id: sequenceId,
        scene_id: sceneId,
        shot_id: shotId,
        entity_type: entityType,
        title,
        content: String(input.content),
        tags,
        source,
        created_at: createdAt
      }
    }
  }
}];

const normalized = $('Normalize Payload').first().json;
return [{
  json: {
    ok: true,
    collection: normalized.collection,
    point_id: normalized.point_id,
    payload: normalized.point.payload,
    qdrant: $json
  }
}];
